export interface QuizOption {
  id: string;
  text: string;
}

export interface QuizQuestion {
  id: number;
  question: string;
  options: QuizOption[];
  answer: string; // usually the correct option text or id
  solution?: string; // Explanation often comes as 'solution' or 'explanation' in datasets
}

export type FetchStatus = 'idle' | 'loading' | 'success' | 'error';

import { QuizQuestion } from '../types';

const DATA_URL = 'https://raw.githubusercontent.com/nsdevaraj/jeeQuestionBank/main/src/data/quiz.json';
const STORAGE_KEY = 'jee_flashcards_cache';

// Mock data to use if fetch fails or for initial render demo
const FALLBACK_DATA: QuizQuestion[] = [
  {
    id: 1,
    question: "If $f(x) = x^2 + 2x + 1$, what is $f(1)$?",
    options: [
      { id: "a", text: "1" },
      { id: "b", text: "2" },
      { id: "c", text: "4" },
      { id: "d", text: "0" }
    ],
    answer: "4",
    solution: "Substitute $x=1$: $f(1) = 1^2 + 2(1) + 1 = 1 + 2 + 1 = 4$."
  },
  {
    id: 2,
    question: "The integral $\\int_{0}^{\\pi} \\sin(x) dx$ is equal to:",
    options: [
      { id: "a", text: "1" },
      { id: "b", text: "2" },
      { id: "c", text: "0" },
      { id: "d", text: "-1" }
    ],
    answer: "2",
    solution: "$\\int \\sin(x) dx = -\\cos(x)$. Evaluated from 0 to $\\pi$: $(-\\cos(\\pi)) - (-\\cos(0)) = -(-1) - (-1) = 1 + 1 = 2$."
  },
   {
    id: 3,
    question: "Which of the following is a unit vector perpendicular to $\\vec{A} = 2\\hat{i} + 3\\hat{j}$?",
    options: [
      { id: "a", text: "$3\\hat{i} - 2\\hat{j}$" },
      { id: "b", text: "$2\\hat{i} - 3\\hat{j}$" },
      { id: "c", text: "$\\hat{k}$" },
      { id: "d", text: "None of these" }
    ],
    answer: "$\\hat{k}$",
    solution: "The vector $\\hat{k}$ is along the z-axis, which is perpendicular to any vector in the xy-plane."
  }
];

export const fetchQuestions = async (): Promise<QuizQuestion[]> => {
  // 1. Try to load from Local Storage (Offline First approach)
  const cached = localStorage.getItem(STORAGE_KEY);
  if (cached) {
    try {
      const parsed = JSON.parse(cached);
      // If we have data, return it immediately, but trigger a re-fetch in background if needed (optional strategy)
      // For now, let's just use cache if valid.
      if (Array.isArray(parsed) && parsed.length > 0) {
        console.log("Loaded from cache");
        return parsed;
      }
    } catch (e) {
      console.warn("Failed to parse cached data", e);
    }
  }

  // 2. Fetch from Network
  try {
    const response = await fetch(DATA_URL);
    if (!response.ok) throw new Error('Network response was not ok');

    const data = await response.json();

    // Validate structure (Basic check)
    if (Array.isArray(data)) {
        // The raw JSON might vary slightly, ensuring we map it correctly if needed.
        // Assuming the raw JSON matches our interface mostly.
        localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
        return data as QuizQuestion[];
    } else {
        throw new Error("Invalid data format");
    }
  } catch (error) {
    console.error("Fetch failed, using fallback data:", error);
    // If we have no cache and fetch fails, use fallback
    if (!cached) {
        return FALLBACK_DATA;
    }
    // If fetch failed but we had bad cache handling earlier, return empty or fallback
    return FALLBACK_DATA;
  }
};

import React, { useMemo } from 'react';
import katex from 'katex';

interface LatexRendererProps {
  text: string;
  className?: string;
  block?: boolean;
}

const LatexRenderer: React.FC<LatexRendererProps> = ({ text, className = "", block = false }) => {
  const renderedContent = useMemo(() => {
    if (!text) return null;

    // Split text by delimiters. We support $...$ for inline and $$...$$ for block.
    // Regex logic:
    // Split by $$...$$ first, then inside those parts, split by $...$
    // This is a simplified parser. 

    const parts = text.split(/(\$\$[\s\S]*?\$\$|\$[\s\S]*?\$)/g);

    return parts.map((part, index) => {
      if (part.startsWith('$$') && part.endsWith('$$')) {
        // Block math
        const math = part.slice(2, -2);
        try {
          const html = katex.renderToString(math, { displayMode: true, throwOnError: false });
          return <span key={index} dangerouslySetInnerHTML={{ __html: html }} />;
        } catch (e) {
          return <span key={index} className="text-red-400">{part}</span>;
        }
      } else if (part.startsWith('$') && part.endsWith('$')) {
        // Inline math
        const math = part.slice(1, -1);
        try {
          const html = katex.renderToString(math, { displayMode: false, throwOnError: false });
          return <span key={index} dangerouslySetInnerHTML={{ __html: html }} />;
        } catch (e) {
          return <span key={index} className="text-red-400">{part}</span>;
        }
      } else {
        // Plain text
        return <span key={index}>{part}</span>;
      }
    });
  }, [text]);

  const Container = block ? 'div' : 'span';

  return (
    <Container className={className}>
      {renderedContent}
    </Container>
  );
};

export default LatexRenderer;

