/**
 * Normalizes disparate JSON data into our strict QuizQuestion format.
 */
const normalizeData = (data: any[]): QuizQuestion[] => {
  return data.map((item: any, index: number) => {
    // 1. Handle different key casings (Question, question, q)
    const qText = item.question || item.Question || item.q || "Question Text Missing";
    const answer = item.answer || item.Answer || item.a || "";
    const solution = item.solution || item.explanation || item.Solution || item.Explanation || "";

    // Extract Subject (normalize to Title Case if possible, or keep as is)
    let subject = item.subject || item.Subject || item.category || item.Category || item.section || "General";

    // 2. Handle options (Array of strings, Array of objects, or Object map)
    let options: QuizOption[] = [];

    if (Array.isArray(item.options)) {
        options = item.options.map((opt: any, idx: number) => {
            // Handle ["Option A", "Option B"]
            if (typeof opt === 'string') {
                return { id: `opt-${index}-${idx}`, text: opt };
            }
            // Handle [{id: "a", text: "..."}] or [{value: "..."}]
            return { 
                id: opt.id || `opt-${index}-${idx}`, 
                text: opt.text || opt.value || opt.label || JSON.stringify(opt) 
            };
        });
    } else if (typeof item.options === 'object' && item.options !== null) {
        // Handle { "a": "Option A", "b": "Option B" }
        options = Object.entries(item.options).map(([key, val]) => ({
            id: key,
            text: String(val)
        }));
    }

    return {
        id: item.id || index + 1,
        question: qText,
        options,
        answer: String(answer), // Ensure string
        solution: String(solution),
        subject: String(subject)
    };
  }).filter(q => q.question && q.options.length > 0); // Filter out empty garbage
};

