export const fetchQuestions = async (): Promise<QuizQuestion[]> => {
  const cached = localStorage.getItem(STORAGE_KEY);

  try {
    const response = await fetch(DATA_URL);
    if (!response.ok) {
        throw new Error(`Network response was not ok: ${response.status}`);
    }

    const rawData = await response.json();
    let dataList: any[] = [];

    // Smart Parser: Find the array inside the JSON
    if (Array.isArray(rawData)) {
        dataList = rawData;
    } else if (typeof rawData === 'object' && rawData !== null) {
        // If it's an object, look for the first key that is an array
        const potentialArrays = Object.values(rawData).filter(val => Array.isArray(val));
        if (potentialArrays.length > 0) {
            // Heuristic: Pick the array with the most items (likely the questions list)
            dataList = potentialArrays.sort((a: any[], b: any[]) => b.length - a.length)[0] as any[];
        }
    }

    if (!Array.isArray(dataList) || dataList.length === 0) {
        throw new Error("Invalid data format: No question array found in response");
    }

    const normalizedData = normalizeData(dataList);

    if (normalizedData.length === 0) {
         throw new Error("Parsed data resulted in 0 valid questions");
    }

    // Success: Cache and return
    console.log(`Fetched ${normalizedData.length} questions from network.`);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(normalizedData));
    return normalizedData;

  } catch (error) {
    console.warn("Fetch failed, attempting to load from cache...", error);

    // Fallback 1: Cache
    if (cached) {
      try {
        const parsedCache = JSON.parse(cached);
        if (Array.isArray(parsedCache) && parsedCache.length > 0) {
          console.log("Loaded from local cache.");
          return parsedCache;
        }
      } catch (e) {
        console.error("Cache corrupted, clearing.");
        localStorage.removeItem(STORAGE_KEY);
      }
    }

    // Fallback 2: Hardcoded Data
    console.warn("Cache empty or invalid, using fallback data.");
    return FALLBACK_DATA;
  }
};

