import React, { useMemo } from 'react';
import katex from 'katex';

interface LatexRendererProps {
  text: string;
  className?: string;
  block?: boolean;
}

const LatexRenderer: React.FC<LatexRendererProps> = ({ text, className = "", block = false }) => {
  const renderedContent = useMemo(() => {
    if (!text) return null;

    // Split text by delimiters. We support $...$ for inline and $$...$$ for block.
    // Regex logic:
    // Split by $$...$$ first, then inside those parts, split by $...$

    const parts = text.split(/(\$\$[\s\S]*?\$\$|\$[\s\S]*?\$)/g);

    return parts.map((part, index) => {
      if (part.startsWith('$$') && part.endsWith('$$')) {
        // Block math
        const math = part.slice(2, -2);
        try {
          const html = katex.renderToString(math, { displayMode: true, throwOnError: false });
          return <span key={index} dangerouslySetInnerHTML={{ __html: html }} />;
        } catch (e) {
          return <span key={index} className="text-red-400">{part}</span>;
        }
      } else if (part.startsWith('$') && part.endsWith('$')) {
        // Inline math
        const math = part.slice(1, -1);
        try {
          const html = katex.renderToString(math, { displayMode: false, throwOnError: false });
          return <span key={index} dangerouslySetInnerHTML={{ __html: html }} />;
        } catch (e) {
          return <span key={index} className="text-red-400">{part}</span>;
        }
      } else {
        // Plain text - render directly. 
        // Note: Newlines will be handled by the parent container's whitespace-pre-wrap style.
        return <span key={index}>{part}</span>;
      }
    });
  }, [text]);

  const Container = block ? 'div' : 'span';

  return (
    <Container className={className}>
      {renderedContent}
    </Container>
  );
};

