import React, { useMemo } from 'react';
import katex from 'katex';
import { marked } from 'marked';

interface LatexRendererProps {
  text: string;
  className?: string;
  block?: boolean;
}

const LatexRenderer: React.FC<LatexRendererProps> = ({ text, className = "", block = false }) => {

  const htmlContent = useMemo(() => {
    if (!text) return "";

    const latexMap = new Map<string, { type: 'block' | 'inline', math: string }>();
    let counter = 0;

    // 1. Protect LaTeX blocks
    // We replace $$...$$ and $...$ with unique tokens so markdown parser doesn't mangle them (e.g. pipes in tables)

    // Replace Block Math $$...$$
    let protectedText = text.replace(/\$\$([\s\S]*?)\$\$/g, (match, math) => {
      const id = `__LATEX_BLOCK_${counter++}__`;
      latexMap.set(id, { type: 'block', math });
      return id;
    });

    // Replace Inline Math $...$
    protectedText = protectedText.replace(/\$([\s\S]*?)\$/g, (match, math) => {
      const id = `__LATEX_INLINE_${counter++}__`;
      latexMap.set(id, { type: 'inline', math });
      return id;
    });

    // 2. Parse Markdown (handles tables, lists, bold, etc.)
    // We treat newlines as breaks (<br>) if they are single newlines, but marked handles standard MD paragraphs.
    // Ensure marked parses tables (GFM is enabled by default in newer marked versions)
    let rawHtml = marked.parse(protectedText) as string;

    // 3. Unprotect and Render LaTeX
    latexMap.forEach((data, id) => {
      try {
        const rendered = katex.renderToString(data.math, {
          displayMode: data.type === 'block',
          throwOnError: false,
          trust: true
        });
        // Replace the token with the rendered HTML
        // Use global replace in case the token appears multiple times (unlikely but safe)
        rawHtml = rawHtml.split(id).join(rendered);
      } catch (e) {
        console.error("KaTeX Error:", e);
        rawHtml = rawHtml.split(id).join(`<span class="text-red-400">${data.math}</span>`);
      }
    });

    return rawHtml;
  }, [text]);

  // Use a div for block content (Markdown generates block elements like <p>, <table>)
  // Use a span only if we are forced to (but typical markdown output expects block context)
  const Container = block ? 'div' : 'span';

  return (
    <Container 
      className={`markdown-content ${className}`}
      dangerouslySetInnerHTML={{ __html: htmlContent }} 
    />
  );
};

